import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import Layout from "../components/Layout";


function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const [filter, setFilter] = useState("recent");
  const [category, setCategory] = useState("all");

  // FETCH QUESTIONS
  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data));
  }, []);

  // FILTER + SORT
  const filtered = questions
    .filter((q) => {
      if (category === "all") return true;
      return q.category === category;
    })
    .sort((a, b) => {
      if (filter === "recent") {
        return new Date(b.createdAt) - new Date(a.createdAt);
      }
      if (filter === "popular") {
        return (b.views || 0) - (a.views || 0);
      }
      return 0;
    });

  return (
    <Layout> {/* ✅ WRAP EVERYTHING */}

      {/* HEADER */}
      <div className="header">
        <div>
          <h2>All Posts</h2>
          <p>{filtered.length} posts available</p>
        </div>

        <Link to="/ask" className="new-post">
          + New Post
        </Link>
      </div>

      {/* POSTS */}
      {filtered.map((q) => (
        <div key={q._id} className="post">

          {/* TOP */}
          <div className="post-top">
            <div className="user">
              <div className="avatar small">
                {q.postedBy?.[0]?.toUpperCase()}
              </div>
              <div>
                <b>{q.postedBy}</b>
                <span> {q.role}</span>
              </div>
            </div>

            <span className="tag">{q.category}</span>
          </div>

          {/* CONTENT */}
          <h3>{q.title}</h3>
          <p>{q.description}</p>

          {/* FILE */}
          {q.file && (
            <a
              href={`http://localhost:5000/uploads/${q.file}`}
              target="_blank"
              rel="noreferrer"
              className="file-link"
            >
              📎 View Attachment
            </a>
          )}

          {/* BOTTOM */}
          <div className="post-bottom">
            <span>👁 {q.views || 0}</span>
            <span>❤️ {q.likes || 0}</span>

            <Link to={`/answers/${q._id}`} className="view-btn">
              View →
            </Link>
          </div>

        </div>
      ))}

    </Layout>
  );
}

export default Dashboard;
